const now = new Date();
const twNow = new Date(now.getTime() + 8 * 3600 * 1000);

function makeDateInfo(twDate) {
  const yyyy = twDate.getUTCFullYear();
  const mm = String(twDate.getUTCMonth() + 1).padStart(2, '0');
  const dd = String(twDate.getUTCDate()).padStart(2, '0');
  const isoDate  = `${yyyy}-${mm}-${dd}`;
  const dateSlug = `${yyyy}_${mm}_${dd}`;
  return {
    isoDate,
    dateSlug,
    xlsUrl: `https://www.taoyuan-airport.com/uploads/fos/${dateSlug}.xls`,
    xlsName: `${dateSlug}.xls`,
    gistFileName: `airport-${isoDate}.json`,
  };
}

const twTomorrow = new Date(twNow.getTime() + 24 * 3600 * 1000);
return [
  { json: makeDateInfo(twNow) },
  { json: makeDateInfo(twTomorrow) },
];

const item = $input.first();

if (item.json?.error || !item.binary?.data) {
  console.log(`[n8n] ⚠️ 跳過 ${item.json.isoDate} — 下載失敗或檔案不存在`);
  return [{ json: { skipRemainder: true, isoDate: item.json.isoDate } }];
}

const binary = item.binary.data;
const mimeType = (binary.mimeType || '').toLowerCase();
const fileSize = binary.fileSize || 0;

if (mimeType.includes('text/html') || mimeType.includes('text/plain') || fileSize < 2000) {
  console.log(`[n8n] ⚠️ 跳過 ${item.json.isoDate} — MIME ${mimeType}，檔案 ${fileSize} bytes`);
  return [{ json: { skipRemainder: true, isoDate: item.json.isoDate } }];
}

const detectedFormat = (mimeType.includes('openxmlformats') || (binary.fileName || '').toLowerCase().endsWith('.xlsx')) ? 'xlsx' : 'xls';
console.log(`[n8n] ✅ ${item.json.isoDate} Binary OK | size=${fileSize} | format=${detectedFormat}`);
return [{ json: { ...item.json, skipRemainder: false, detectedFormat }, binary: item.binary }];

const items = $input.all();

function findHourKey(rows) {
  if (!rows.length) return null;
  const keys = Object.keys(rows[0].json);
  for (const key of keys) {
    const hits = rows.filter(r => {
      const v = parseInt(String(r.json[key] ?? ''), 10);
      return !isNaN(v) && v >= 0 && v <= 23;
    }).length;
    if (hits >= 20) return key;
  }
  return null;
}

// 嘗試從欄位名稱找入境/出境欄
function findDirectionalCols(rows) {
  if (!rows.length) return null;
  const keys = Object.keys(rows[0].json);
  const arrKey = keys.find(k => /入境|arrival|arr/i.test(k));
  const depKey = keys.find(k => /出境|departure|dep/i.test(k));
  if (arrKey && depKey && arrKey !== depKey) return { arrKey, depKey };
  // fallback: __EMPTY / __EMPTY_1
  if (keys.includes('__EMPTY') && keys.includes('__EMPTY_1')) return { arrKey: '__EMPTY', depKey: '__EMPTY_1' };
  return null;
}

const hourKey = findHourKey(items);
if (!hourKey) throw new Error('無法找到時段欄位，XLS 格式可能已變更');

const dirCols = findDirectionalCols(items);
const parsed = [];
for (const item of items) {
  const row = item.json;
  const hour = parseInt(String(row[hourKey] ?? ''), 10);
  if (isNaN(hour) || hour < 0 || hour > 23) continue;
  const arr = dirCols ? (Number(row[dirCols.arrKey]) || 0) : 0;
  const dep = dirCols ? (Number(row[dirCols.depKey]) || 0) : 0;
  parsed.push({ hour, arr, dep });
}

// 偵測是否有真實的方向分項資料：
// - dep 全為 0 → 只有一欄合計，無分項
// - arr === dep for all data hours → 兩欄讀到相同值，無分項
const dataHours = parsed.filter(r => r.arr > 0 || r.dep > 0);
const allDepZero     = dataHours.every(r => r.dep === 0);
const arrDepIdentical = dataHours.length > 0 && dataHours.every(r => r.arr === r.dep);
const hasRealDirectional = dataHours.length > 0 && !allDepZero && !arrDepIdentical;

let hours;
if (hasRealDirectional) {
  // 有真實的入境/出境分項，輸出三筆
  hours = Array.from({ length: 24 }, (_, h) => {
    const found = parsed.find(r => r.hour === h) ?? { hour: h, arr: 0, dep: 0 };
    return [
      { hour: h, forecastCount: found.arr,             terminal: 'all', direction: 'arrival' },
      { hour: h, forecastCount: found.dep,             terminal: 'all', direction: 'departure' },
      { hour: h, forecastCount: found.arr + found.dep, terminal: 'all', direction: 'all' },
    ];
  }).flat();
} else {
  // 無分項 → 只輸出合計（避免前端顯示相同數字的假分項）
  hours = Array.from({ length: 24 }, (_, h) => {
    const found = parsed.find(r => r.hour === h) ?? { hour: h, arr: 0, dep: 0 };
    const total = arrDepIdentical ? found.arr : (found.arr + found.dep);
    return [{ hour: h, forecastCount: total, terminal: 'all', direction: 'all' }];
  }).flat();
}

const { isoDate, xlsName, gistFileName } = $('驗證下載結果').first().json;
const mode = hasRealDirectional ? '3 方向' : '合計';
console.log(`[n8n] 📊 ${isoDate} 解析完成，共 ${hours.length} 筆（${mode}）`);
return [{ json: { date: isoDate, sourceFile: xlsName, gistFileName, hours } }];

// 計算 8~60 天前的日期作為待清理檔名（PATCH null 即刪除 Gist 中該檔案）
const files = {};
for (let i = 8; i <= 60; i++) {
  const d = new Date(Date.now() + 8 * 3600 * 1000 - i * 24 * 3600 * 1000);
  const yyyy = d.getUTCFullYear();
  const mm = String(d.getUTCMonth() + 1).padStart(2, '0');
  const dd = String(d.getUTCDate()).padStart(2, '0');
  files[`airport-${yyyy}-${mm}-${dd}.json`] = null;
}
return [{ json: { filesToDelete: files } }];

const g = $input.first().json;
console.log('[n8n] ✅ 全部完成 | gist updated_at:', g.updated_at ?? '(清理完成)');
return [{ json: { ok: true } }];
